#!/usr/bin/env python3
import hashlib

WORDLIST = ["password", "123456", "admin", "qwerty", "letmein", "root"]
TARGET = "5f4dcc3b5aa765d61d8327deb882cf99"  # MD5

for word in WORDLIST:
    if hashlib.md5(word.encode()).hexdigest() == TARGET:
        print(f"[+] Şifre bulundu: {word}")
        break
else:
    print("[-] Wordlist'te bulunamadı")
